<h1 class="h5">Plan: <?= e($plan['nombre'] ?? '') ?> / Asignación de funcionalidades</h1>
<form method="POST"><?= csrf_campo() ?><div class="table-responsive"><table class="table table-sm"><thead><tr><th>Funcionalidad</th><th>Activo</th><th>Valor numérico</th><th>Ilimitado</th></tr></thead><tbody><?php foreach($funcionalidades as $f): $a = $mapa[$f['id']] ?? null; ?><tr><td><?= e($f['nombre']) ?><div class="small text-muted"><?= e($f['codigo_interno']) ?></div></td><td><input type="checkbox" name="funcionalidades[<?= $f['id'] ?>][activo]" <?= ($a['activo'] ?? 0) ? 'checked':'' ?>></td><td><input class="form-control form-control-sm" type="number" name="funcionalidades[<?= $f['id'] ?>][valor_numerico]" value="<?= e((string)($a['valor_numerico'] ?? 0)) ?>"></td><td><input type="checkbox" name="funcionalidades[<?= $f['id'] ?>][es_ilimitado]" <?= ($a['es_ilimitado'] ?? 0) ? 'checked':'' ?>></td></tr><?php endforeach; ?></tbody></table></div><button class="btn btn-primary btn-sm">Guardar asignaciones</button></form>
